package main

import (
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"

	"github.com/gin-gonic/gin"
)

const publicDir = "./public"

func init() {
	if err := os.MkdirAll(publicDir, 0755); err != nil {
		fmt.Println("Error creating public directory:", err)
		os.Exit(1)
	}
}

func uploadHandler(c *gin.Context) {
	form, err := c.MultipartForm()
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid form data"})
		return
	}

	files := form.File["files"]
	for _, fileHeader := range files {
		file, err := fileHeader.Open()
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Error opening file"})
			return
		}
		defer file.Close()

		ext := filepath.Ext(fileHeader.Filename)
		if ext == "" || !isValidFileType(ext) {
			c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid file type"})
			return
		}

		filePath := filepath.Join(publicDir, fileHeader.Filename)
		out, err := os.Create(filePath)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Error saving file"})
			return
		}
		defer out.Close()

		_, err = io.Copy(out, file)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Error copying file"})
			return
		}

		c.JSON(http.StatusOK, gin.H{"file_path": filePath})
	}
}

func isValidFileType(ext string) bool {
	validTypes := []string{".jpg", ".jpeg", ".png", ".gif", ".doc", ".docx", ".pdf", ".zip", ".rar"}
	for _, validType := range validTypes {
		if ext == validType {
			return true
		}
	}
	return false
}

func main() {
	r := gin.Default()
	r.POST("/upload", uploadHandler)
	r.Run(":8080")
}